import React, { Component } from 'react';
import './dash.css';

export default class Dash extends Component {

    constructor(props) {
        super(props);

        this.state = {
            items: null,
            adding: false,
            tag: "",
            link: ""
        }

        this.onClickFactorySettings = this.onClickFactorySettings.bind(this);
        this.onClickSave = this.onClickSave.bind(this);
    }

    componentDidMount() {
        promises.items_get()
            .then(res => {
                this.setState({ items: res })
            })
            .catch(res => {
                promises.items_set(items_const)
                    .then(res => {
                        promises.items_get()
                            .then(res => {
                                this.setState({ items: res })
                            })
                            .catch(res => {
                                console.log("LOCALSTORAGE ERROR");
                            })
                    })
            })
    }

    onClickFactorySettings() {
        promises.items_remove().
            then(res => {
                promises.items_set(items_const)
                    .then(res => {
                        promises.items_get()
                            .then(res => {
                                this.setState({ items: res })
                            })
                    })
            })
    }

    onClickSave() {
        promises.items_get().then(res=>{
            let r = res;
            let l = this.state.link;
            if ( !l.startsWith("https://") && !l.startsWith("http://")) {
                l = "http://"+l;
            }
            r.push({tag:this.state.tag, link:l});
            promises.items_set(r).then(res=>{
                this.setState({
                    items : r,
                    adding : false
                });
            });
        });
    }

    render() {
        let c = [];
        let items = this.state.items;

        if (items === null || items === undefined) {
            return (<div></div>);
        }

        if (this.state.adding === true) {
            return (
                <div className="Dash">
                    <div className="Dash-Header">
                        <div className="Dash-Header-Item" onClick={() => this.setState({ adding: false, tag: "", link: "" })}>close</div>
                        <div className="Dash-Header-Item" onClick={this.onClickSave}>save</div>
                    </div>
                    <div className="Dash-Content" style={{ height: (height - 50) + "px" }}>
                        <div className="Dash-Item">
                            <label>tag :</label> 
                            <input value={this.state.tag} onChange={(e)=>this.setState({tag: e.target.value})}/>
                        </div>
                        <div className="Dash-Item">
                            <label>link :</label> 
                            <input value={this.state.link} onChange={(e)=>this.setState({link: e.target.value})}/>
                        </div>
                    </div>
                </div>
            );
        }

        items.sort((a, b) => { return (a.tag > b.tag) ? 1 : -1 });

        for (let i = 0; i < items.length; i++) {
            c.push(
                <a href={items[i].link} className="Dash-Item" key={i}>
                    <div style={{ width: "90%" }} >{items[i].tag.toLowerCase()}</div>
                </a>
            );
        }

        return (
            <div className="Dash">
                <div className="Dash-Header">
                    <div className="Dash-Header-Item" onClick={this.onClickFactorySettings}>factory_settings</div>
                    <div className="Dash-Header-Item" onClick={() => this.setState({ adding: true })}>add</div>
                </div>
                <div className="Dash-Content" style={{ height: (height - 50) + "px" }}>
                    {c}
                </div>
            </div>
        );
    }
}

const height = window.innerHeight;

const promises = {
    items_get: () => {
        return new Promise(
            (res, rej) => {
                console.log("ITEMS GET PROMISE");
                let items = localStorage.getItem(items_key);
                if (items !== null) res(JSON.parse(items));
                rej();
            }
        );
    },

    items_set: (items) => {
        return new Promise(
            (res, rej) => {
                console.log("ITEMS SET PROMISE");
                localStorage.setItem(items_key, JSON.stringify(items));
                res();
            }
        );
    },

    items_remove: () => {
        return new Promise(
            (res, rej) => {
                console.log("ITEMS REMOVE PROMISE");
                localStorage.removeItem(items_key);
                res();
            }
        );
    }
}

